        const profileId = String(data.deviceInfo.deviceProfileId || '').trim();
        const kiwiProfileId = String(env.get('CHIRPSTACK_PROFILE_KIWI') || '').trim();
        const cloverProfileId = String(env.get('CHIRPSTACK_PROFILE_CLOVER') || '').trim();
