/**
 * KIWI UPLINK SIM (15min) – MULTI-DEVICE (UPPERCASE DevEUI)
 *
 * Simulates 6 KIWI-like devices with realistic WM1/WM2 dynamics + lux + temp + RH.
 * Device naming convention:
 *   farm_<farmId>_sensor_<n>_type_KIWI
 *
 * Output payload fields (compatible with your Process Data):
 *   payload.deviceInfo.devEui        (NOW UPPERCASE)
 *   payload.deviceInfo.deviceName
 *   payload.time
 *   payload.object.input5_frequency
 *   payload.object.input6_frequency
 *   payload.object.light_intensity
 *   payload.object.ambient_temperature
 *   payload.object.relative_humidity
 */

function clamp(x, a, b) { return Math.max(a, Math.min(b, x)); }

// ---------- deterministic devEUI generation ----------
function hash32(str) {
    // FNV-1a 32-bit
    let h = 0x811c9dc5;
    for (let i = 0; i < str.length; i++) {
        h ^= str.charCodeAt(i);
        h = (h * 0x01000193) >>> 0;
    }
    return h >>> 0;
}

function hex8(n) {
    return (n >>> 0).toString(16).padStart(8, "0");
}

function makeDevEuiFromName(name) {
    // Create 16-hex char EUI from two 32-bit hashes + some structure
    const h1 = hash32("A|" + name);
    const h2 = hash32("B|" + name);
    const h3 = hash32("C|" + name);
    const h4 = hash32("D|" + name);

    const p1 = (h1 ^ (h3 >>> 1)) >>> 0;
    const p2 = (h2 ^ (h4 >>> 1)) >>> 0;

    // IMPORTANT: normalize to UPPERCASE here
    return (hex8(p1) + hex8(p2)).toUpperCase();
}

// ---------- kPa <-> Hz ----------
function kPaToHz(kpa) {
    const K = clamp(kpa, 0, 200);
    let hz;

    if (K <= 9) {
        hz = 4330 + (9 - K) / 0.004286;
        hz = clamp(hz, 4330, 6430);
    } else if (K <= 15) {
        hz = 2820 + (15 - K) / 0.003974;
        hz = clamp(hz, 2820, 4330);
    } else if (K <= 35) {
        hz = 1110 + (35 - K) / 0.01170;
        hz = clamp(hz, 1110, 2820);
    } else if (K <= 55) {
        hz = 770 + (55 - K) / 0.05884;
        hz = clamp(hz, 770, 1110);
    } else if (K <= 75) {
        hz = 600 + (75 - K) / 0.1176;
        hz = clamp(hz, 600, 770);
    } else if (K <= 100) {
        hz = 485 + (100 - K) / 0.2174;
        hz = clamp(hz, 485, 600);
    } else {
        hz = 293 + (200 - K) / 0.5208;
        hz = clamp(hz, 293, 485);
    }

    // Small measurement noise
    hz += (Math.random() * 8 - 4); // +/- 4 Hz
    hz = Math.round(clamp(hz, 250, 7000));
    return hz;
}

// ---------- lux / temp / RH ----------
function luxFromLocalTime(d) {
    const h = d.getHours() + d.getMinutes() / 60;
    const sunrise = 6.25;
    const sunset = 18.75;

    if (h < sunrise || h > sunset) return Math.max(0, Math.round(Math.random() * 3));

    const x = (h - sunrise) / (sunset - sunrise) * Math.PI;
    const base = Math.sin(x); // 0..1..0
    const peakLux = 65000;
    const cloudFactor = 0.6 + Math.random() * 0.4;
    const noise = 0.95 + Math.random() * 0.10;

    return Math.round(peakLux * base * cloudFactor * noise);
}

function tempRhFromLocalTime(d, lux) {
    const h = d.getHours() + d.getMinutes() / 60;
    const luxRatio = clamp((lux || 0) / 65000, 0, 1);

    // Temperature: peak around ~15:00
    const tMin = 20.5;
    const tMax = 31.0;
    const amp = tMax - tMin;

    const phase = ((h - 15) / 24) * 2 * Math.PI;
    const tempCycle = 0.5 * (1 + Math.cos(phase)); // 0..1

    const sunBoost = 1.2 * (luxRatio - 0.5);
    let temp = tMin + amp * tempCycle + sunBoost;
    temp += (Math.random() * 0.6 - 0.3);
    temp = clamp(temp, 18, 35);

    // RH inverse to tempCycle
    const rhMax = 92;
    const rhMin = 58;
    const invCycle = 1 - tempCycle;

    let rh = rhMin + (rhMax - rhMin) * invCycle;
    rh += (1 - luxRatio) * 4;
    rh += (Math.random() * 3 - 1.5);
    rh = clamp(rh, 35, 100);

    return {
        ambient_temperature: Math.round(temp * 10) / 10,
        relative_humidity: Math.round(rh * 10) / 10
    };
}

// ---------- per-device dynamics ----------
function initDeviceState(deviceName, devEui, profile) {
    return {
        deviceName,
        devEui,

        wm1_kpa: profile.wm1_start,
        wm2_kpa: profile.wm2_start,

        wm1_target: profile.wm1_target,
        wm2_target: profile.wm2_target,

        wettingActive: false,
        wettingStepsLeft: 0,
        wettingIntensity: 0,

        wm2_disconnectActive: false,
        wm2_disconnectStepsLeft: 0,

        wetProb: profile.wetProb,
        wm2DiscProb: profile.wm2DiscProb,

        dryBiasWm1: 0.15 + Math.random() * 0.25,
        dryBiasWm2: 0.25 + Math.random() * 0.45
    };
}

function stepDeviceState(st) {
    const dryStepWm1 = st.dryBiasWm1 + (Math.random() * 0.6);
    const dryStepWm2 = st.dryBiasWm2 + (Math.random() * 1.0);

    const noiseWm1 = (Math.random() * 0.6 - 0.3);
    const noiseWm2 = (Math.random() * 0.9 - 0.45);

    if (Math.random() < 0.035) st.wm1_target = clamp(st.wm1_target + (Math.random() * 4 - 2), 12, 55);
    if (Math.random() < 0.055) st.wm2_target = clamp(st.wm2_target + (Math.random() * 10 - 4), 18, 135);

    if (!st.wettingActive && Math.random() < st.wetProb) {
        st.wettingActive = true;
        st.wettingStepsLeft = 6 + Math.floor(Math.random() * 10);
        st.wettingIntensity = 8 + Math.random() * 28;
    }

    if (!st.wm2_disconnectActive && Math.random() < st.wm2DiscProb) {
        st.wm2_disconnectActive = true;
        st.wm2_disconnectStepsLeft = 8 + Math.floor(Math.random() * 24);
    }

    if (st.wettingActive && st.wettingStepsLeft > 0) {
        const stepFrac = st.wettingStepsLeft / Math.max(1, (st.wettingStepsLeft + 4));
        const drop = (st.wettingIntensity / (st.wettingStepsLeft + 2)) * (1.1 - 0.4 * stepFrac);

        st.wm1_kpa -= drop * 0.6;
        st.wm2_kpa -= drop * 0.9;

        st.wettingStepsLeft -= 1;

        if (st.wettingStepsLeft <= 0) {
            st.wettingActive = false;
            st.wettingIntensity = 0;
            st.wm1_target = clamp(st.wm1_target - (2 + Math.random() * 6), 8, 45);
            st.wm2_target = clamp(st.wm2_target - (4 + Math.random() * 10), 12, 110);
        }
    } else {
        st.wm1_kpa += dryStepWm1;
        st.wm2_kpa += dryStepWm2;

        st.wm1_kpa += (st.wm1_target - st.wm1_kpa) * 0.03;
        st.wm2_kpa += (st.wm2_target - st.wm2_kpa) * 0.03;
    }

    st.wm1_kpa = clamp(st.wm1_kpa + noiseWm1, 0, 150);
    st.wm2_kpa = clamp(st.wm2_kpa + noiseWm2, 0, 150);

    let wm2EffectiveKpa = st.wm2_kpa;
    if (st.wm2_disconnectActive) {
        wm2EffectiveKpa = 200;
        st.wm2_disconnectStepsLeft -= 1;
        if (st.wm2_disconnectStepsLeft <= 0) st.wm2_disconnectActive = false;
    }

    return { wm1: st.wm1_kpa, wm2: wm2EffectiveKpa };
}

