function convertHzToKPa(inputFrequency) {
    if (typeof inputFrequency !== 'number' || isNaN(inputFrequency)) return null;
    if (inputFrequency > 6430) return 0;
    if (inputFrequency >= 4330 && inputFrequency <= 6430) return 9 - (inputFrequency - 4330) * 0.004286;
    if (inputFrequency >= 2820 && inputFrequency <= 4330) return 15 - (inputFrequency - 2820) * 0.003974;
    if (inputFrequency >= 1110 && inputFrequency <= 2820) return 35 - (inputFrequency - 1110) * 0.01170;
    if (inputFrequency >= 770 && inputFrequency <= 1110) return 55 - (inputFrequency - 770) * 0.05884;
    if (inputFrequency >= 600 && inputFrequency <= 770) return 75 - (inputFrequency - 600) * 0.1176;
    if (inputFrequency >= 485 && inputFrequency <= 600) return 100 - (inputFrequency - 485) * 0.2174;
    if (inputFrequency >= 293 && inputFrequency <= 485) return 200 - (inputFrequency - 293) * 0.5208;
    if (inputFrequency < 293) return 200;
    return null;
}

function detectLsn50ModeCode(b64) {
    try {
        var buf = Buffer.from(b64, 'base64');
        if (buf.length < 7) return null;
        var rawMode = (buf[6] >> 2) & 0x1F;
        var modeCode = rawMode + 1;
        return (modeCode >= 1 && modeCode <= 9) ? modeCode : null;
    } catch (e) {
        return null;
    }
}

function lsn50ModeLabel(modeCode) {
    return modeCode != null && modeCode >= 1 && modeCode <= 9 ? ('MOD' + modeCode) : null;
}

function getProfileKind(deviceInfo) {
    var profileName = String((deviceInfo && deviceInfo.deviceProfileName) || '').toUpperCase();
    var profileId = String((deviceInfo && deviceInfo.deviceProfileId) || '').trim();
    var kiwiProfiles = [String(env.get('CHIRPSTACK_PROFILE_KIWI') || '').trim(), 'ae4194a5-56f8-4ca0-a129-8ad958505e1e'].filter(Boolean);
    var cloverProfiles = [String(env.get('CHIRPSTACK_PROFILE_CLOVER') || '').trim(), '46bdcc01-86db-41bd-bbf8-78cc439edae5'].filter(Boolean);
    var lsn50Profiles = [String(env.get('CHIRPSTACK_PROFILE_LSN50') || '').trim()].filter(Boolean);
