      const dl=new Date(zs.recovery_verification_deadline);
      const recoveryThreshold=(calibration.thresholds.mild||CALIBRATIONS.default.thresholds.mild)*(phenoMod>0?phenoMod:1.0);
      const verifiableTrees=nonRef.filter(t=>!t.is_ref&&t.baseline_complete===1&&!t.low_confidence_day&&t.twd_night_um!=null&&t.mds_norm!=null);
