    const vpdOverrideSummary={
      downgraded_tree_count:monitoredTrees.filter(t=>t.stress_adjustment==='vpd_downgrade').length,
      upgraded_tree_count:monitoredTrees.filter(t=>t.stress_adjustment==='vpd_upgrade').length
    };
    const sdVpdSummary={
      status:comparableSdVpdTrees.length?(comparableSdVpdTrees.some(t=>t.sd_vpd_decoupled)?'decoupled':'coupled'):'insufficient_data',
      baseline_r2:comparableSdVpdTrees.length?round(avg(comparableSdVpdTrees.map(t=>t.sd_vpd_r2_baseline)),3):null,
      rolling_14d_r2:comparableSdVpdTrees.length?round(avg(comparableSdVpdTrees.map(t=>t.sd_vpd_r2_current)),3):null,
      comparable_tree_count:comparableSdVpdTrees.length,
      decoupled_tree_count:comparableSdVpdTrees.filter(t=>t.sd_vpd_decoupled).length
    };
    const recJson=JSON.stringify({
      zone_id:String(zone.zone_id),
      date:ANALYTICS_DATE,
      trees:trees.map(t=>({
        device_eui:t.deveui,
