        twd_night_um:t.twd_night_um,
        twd_day_um:t.twd_day_um,
        twd_norm_night:t.twd_norm_night,
        mds_norm:t.mds_norm,
        recovery_ratio_smoothed:t.recovery_ratio_smoothed,
        stress_level_pre_vpd:t.stress_level_pre_vpd,
        stress_level:t.stress,
        tree_state_v5:t.tree_state_v5,
        stress_adjustment:t.stress_adjustment,
        data_quality:t.quality,
        baseline_complete:t.baseline_complete,
        mds_ref_um:t.mds_ref_um,
        confidence_score:t.confidence_score,
        low_confidence_day:t.low_confidence_day,
        sd_vpd_r2_baseline:t.sd_vpd_r2_baseline,
        sd_vpd_r2_current:t.sd_vpd_r2_current,
        sd_vpd_decoupled:t.sd_vpd_decoupled
      })),
      zone_stress:zoneSt,
      usable_tree_count:aggregation.usableTreeCount,
      low_confidence_tree_count:aggregation.lowConfidenceTreeCount,
      outlier_filtered_tree_count:aggregation.outlierFilteredTreeCount,
      zone_confidence_score:aggregation.zoneConfidenceScore,
      schedule_trigger_metric:schedule?.trigger_metric||null,
      schedule_threshold_kpa:schedule?.threshold_kpa??null,
      action,
      reasoning,
      vpd,
      vpd_override_summary:vpdOverrideSummary,
      sd_vpd_summary:sdVpdSummary,
      rain,
      rain_suppression_active:zs.rain_suppression_active?1:0,
      recovery_verification_active:zs.recovery_verification_active?1:0
    });

    await run(`INSERT OR REPLACE INTO zone_daily_recommendations(zone_id,date,zone_stress_summary,rainfall_mm,water_delivered_liters,irrigation_action,action_reasoning,recommendation_json,computed_at,rain_suppression_active,recovery_verification_active,vpd_max_kpa,vpd_source,irrigation_window_json,usable_tree_count,low_confidence_tree_count,outlier_filtered_tree_count,zone_confidence_score)VALUES(${zone.zone_id},${s(ANALYTICS_DATE)},${s(zoneSt)},${n(rain.daily_mm)},${n(localFlowLiters||0)},${s(action)},${s(reasoning)},${s(recJson)},${s(COMPUTED_AT)},${n(zs.rain_suppression_active?1:0)},${n(zs.recovery_verification_active?1:0)},${n(vpd.vpd_max_kpa)},${s(vpd.vpd_source)},${s(JSON.stringify({start:'17:00',end:'24:00',timezone:zoneTimezone}))},${n(aggregation.usableTreeCount)},${n(aggregation.lowConfidenceTreeCount)},${n(aggregation.outlierFilteredTreeCount)},${n(aggregation.zoneConfidenceScore)})`);
    await run(`INSERT OR REPLACE INTO zone_irrigation_state(zone_id,rain_suppression_active,rain_suppression_start,rain_suppression_timeout_h,pre_rain_twd_norm_avg,recovery_verification_active,recovery_verification_start,recovery_verification_deadline,consecutive_increases,current_volume_liters,updated_at)VALUES(${zone.zone_id},${n(zs.rain_suppression_active?1:0)},${s(zs.rain_suppression_start||null)},${n(zs.rain_suppression_timeout_h||48)},${n(zs.pre_rain_twd_norm_avg||null)},${n(zs.recovery_verification_active?1:0)},${s(zs.recovery_verification_start||null)},${s(zs.recovery_verification_deadline||null)},${n(zs.consecutive_increases||0)},${n(zs.current_volume_liters||0)},${s(COMPUTED_AT)})`);

