  }

  const payloadDate=summary[0]?.date||shiftDateIso(COMPUTED_AT.slice(0,10),-1);
  node.status({fill:'green',shape:'dot',text:payloadDate+' — '+zones.length+' zone(s) v5'});
  msg.payload={success:true,date:payloadDate,zones:summary};
  await close();
  return msg;
}catch(err){
  node.error('Analytics v5: '+err.message+'\n'+err.stack);
  node.status({fill:'red',shape:'ring',text:err.message});
  try{await close();}catch(e){}
  return null;
}
