function fromBase64Url(input) { let value = String(input || '').replace(/-/g, '+').replace(/_/g, '/'); while (value.length % 4) value += '='; return Buffer.from(value, 'base64'); }
function verifyBearer(authHeader) {
  if (!authHeader || !authHeader.startsWith('Bearer ')) { const err = new Error('Unauthorized'); err.statusCode = 401; throw err; }
  const token = authHeader.substring(7).trim(); const parts = token.split('.');
  if (parts.length !== 2 || !parts[0] || !parts[1]) { const err = new Error('Invalid token'); err.statusCode = 401; throw err; }
  const payloadB64 = parts[0]; const sig = parts[1];
  const expectedSig = toBase64Url(crypto.createHmac('sha256', getAuthSecret()).update(payloadB64).digest());
  const sigBuf = Buffer.from(sig, 'utf8'); const expectedBuf = Buffer.from(expectedSig, 'utf8');
  if (sigBuf.length !== expectedBuf.length || !crypto.timingSafeEqual(sigBuf, expectedBuf)) { const err = new Error('Invalid token'); err.statusCode = 401; throw err; }
  const payload = JSON.parse(fromBase64Url(payloadB64).toString('utf8'));
  const userId = Number(payload.userId); const username = String(payload.username || '').trim(); const exp = Number(payload.exp || 0);
  if (!Number.isFinite(userId) || !username || (exp && Date.now() > exp)) { const err = new Error(exp && Date.now() > exp ? 'Token expired' : 'Invalid token'); err.statusCode = 401; throw err; }
  return { userId, username };
}
