    );
    deviceRows = [...deviceRows, ...s2120DevRows];
  }

  const nowIso = new Date().toISOString();
  const location = resolveLocation(zone);
  const local = buildLocalEnvironment(deviceRows, nowIso);
  const localOnline = await resolveOnlineCurrent(zone, location, nowIso);
  const localForecast = await resolveForecast(zone, location, zone.phenological_stage, nowIso);
  const localAgronomic = buildAgronomic(local, localOnline, localForecast, zone.phenological_stage);
  const water = await buildWaterEnvironment(zone, deviceRows, local, localAgronomic, localForecast, nowIso);
  const schedulingMode = normalizeSchedulingMode(zone.scheduling_mode);
