      online: sharedSummary.online || localOnline,
      agronomic: sharedSummary.agronomic || localAgronomic,
      forecast: sharedSummary.forecast || localForecast,
      display: buildDisplayStatus(
        displayMode,
        schedulingMode,
        displayMode === 'shared_server' || displayMode === 'shared_server_stale' ? 'OSI Server' : 'Local fallback',
        trimToNull(sharedDisplay.sharedGeneratedAt) || trimToNull(sharedSummary.generatedAt) || cachedShared && cachedShared.sharedGeneratedAt || nowIso,
        trimToNull(sharedDisplay.sharedObservedAt) || cachedShared && cachedShared.sharedObservedAt || (sharedSummary.water && sharedSummary.water.observedAt) || null,
        sharedBundleLastReceivedAt || trimToNull(sharedDisplay.lastReceivedAt) || nowIso,
        displayFallbackReason || trimToNull(sharedDisplay.fallbackReason)
      ),
      drift: computeRecommendationDrift(zone, water, sharedSummary.water || null, schedulingMode)
    };
  } else {
    summary = {
      zoneId: Number(zone.id),
      zoneName: zone.name || null,
      generatedAt: nowIso,
      location: {
        latitude: location.latitude,
        longitude: location.longitude,
        timezone: location.timezone,
        source: location.source
      },
      water,
      local,
      online: localOnline,
      agronomic: localAgronomic,
      forecast: localForecast,
      display: buildDisplayStatus(
        displayMode,
        schedulingMode,
        displayMode === 'unlinked_local' ? 'Local environment' : 'Local fallback',
        null,
        water && water.observedAt,
        sharedBundleLastReceivedAt,
        displayFallbackReason
      ),
      drift: null
    };
  }

  await close();
  return respond(summary, 200);
} catch (error) {
  try { await close(); } catch (_) {}
  return respond({ error: error.message }, error.statusCode || 500);
